+        String testSrc = System.getProperty("test.src");
+
+        // Compile ExampleForClassPath to hidden/
+        Path hiddenDir = Path.of("hidden");
+        Files.createDirectories(hiddenDir);
+        CompilerUtils.compile(Path.of(testSrc, "..", "ExampleForClassPath.java"), hiddenDir);
+
+        // Compile InstrumentationHandoff
+        Path classesDir = Path.of("classes");
