+        CompilerUtils.compile(Path.of(testSrc, "..", "InstrumentationHandoff.java"), classesDir);
+
+        // Create Agent.jar
+        Manifest man = new Manifest();
+        Attributes attrs = man.getMainAttributes();
+        attrs.put(Attributes.Name.MANIFEST_VERSION, "1.0");
