+        attrs.putValue("Premain-Class", "InstrumentationHandoff");
+        JarUtils.createJarFile(Path.of("Agent.jar"), man, classesDir,
+            Path.of("InstrumentationHandoff.class"));
+
+        System.out.println("Agent.jar built successfully");
